async function safeRequest<T>(path: string, fallback: T, timeoutMs = 9000) {
  try {
    return { data: await requestWithTimeout<T>(path, { headers: authHeaders() }, timeoutMs), ok: true }
  } catch (error) {
    console.warn(`[Dashboard] ${path}`, error)
    return { data: fallback, ok: false }
  }
}

// 词云组件（简化版）
function WordCloud({ data, maxWords = 20 }: { data: Record<string, number>; maxWords?: number }) {
  const entries = Object.entries(data).sort((a, b) => b[1] - a[1]).slice(0, maxWords)
  
  if (!entries.length) return <EmptyBox text="暂无兴趣数据" />
  
  const maxValue = Math.max(...entries.map(([_, v]) => v))
  const minValue = Math.min(...entries.map(([_, v]) => v))
  const sizeRange = { min: 14, max: 48 }
  
  return (
    <div className="flex flex-wrap gap-3 p-4">
      {entries.map(([word, value], index) => {
        const normalized = maxValue === minValue ? 0.5 : (value - minValue) / (maxValue - minValue)
        const size = sizeRange.min + normalized * (sizeRange.max - sizeRange.min)
        const color = wordCloudColors[index % wordCloudColors.length]
        
        return (
          <span
            key={word}
            className="px-4 py-2 rounded-full font-medium transition-all duration-300 hover:scale-110 cursor-pointer"
            style={{
              fontSize: `${size}px`,
              color: color,
              backgroundColor: `${color}15`,
              border: `1px solid ${color}30`
            }}
          >
            {word}
            <span className="ml-2 text-xs opacity-60">{value}</span>
          </span>
        )
      })}
    </div>
  )
}

// 雷达图组件
function RadarChartComponent({ data }: { data: Record<string, number> }) {
  const entries = Object.entries(data)
  if (!entries.length) return <EmptyBox text="暂无情感数据" />
  
  const chartData = entries.map(([subject, value]) => ({
    subject,
    A: value,
    fullMark: Math.max(...entries.map(([_, v]) => v))
  }))
  
  return (
    <div className="h-80 w-full">
      <ResponsiveContainer width="100%" height="100%">
        <RadarChart cx="50%" cy="50%" outerRadius="70%" data={chartData}>
          <PolarGrid stroke="#e5e7eb" />
          <PolarAngleAxis dataKey="subject" tick={{ fontSize: 12 }} />
          <PolarRadiusAxis angle={90} domain={[0, 'auto']} tick={false} axisLine={false} />
          <Radar
            name="情感分布"
            dataKey="A"
            stroke="#007A2F"
            fill="#007A2F"
            fillOpacity={0.3}
          />
          <Tooltip 
            contentStyle={{ borderRadius: '8px', border: 'none', boxShadow: '0 4px 6px -1px rgb(0 0 0 / 0.1)' }}
          />
        </RadarChart>
      </ResponsiveContainer>
    </div>
  )
}

